$ErrorActionPreference='SilentlyContinue';$o=[ordered]@{};$o.time=(Get-Date -Format o);$o.user="$env:USERDOMAIN\$env:USERNAME";$o.hostname=$env:COMPUTERNAME;$o.arch=$env:PROCESSOR_ARCHITECTURE;$o.os=(Get-ItemProperty 'HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion'|%{"$($_.ProductName) $($_.DisplayVersion) build $($_.CurrentBuild).$($_.UBR)"});$o.ip=(Get-NetIPAddress -AddressFamily IPv4|?{$_.IPAddress -notlike '169.254*' -and $_.IPAddress -ne '127.0.0.1'}|select -Expand IPAddress);$o.dns=(Get-DnsClientServerAddress -AddressFamily IPv4|select -Expand ServerAddresses -Unique);$o.routes=(Get-NetRoute -DestinationPrefix '0.0.0.0/0'|select ifIndex,NextHop,RouteMetric);$o.ports=(Get-NetTCPConnection -State Listen|select LocalAddress,LocalPort,OwningProcess,@{n='Process';e={(Get-Process -Id $_.OwningProcess).ProcessName}});$o.established=(Get-NetTCPConnection -State Established|select LocalAddress,LocalPort,RemoteAddress,RemotePort,OwningProcess);$o.procs=(Get-Process|sort CPU -desc|select -first 25 Id,ProcessName,CPU,Path);$o.users=(quser 2>$null);$o.admin=([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole('Administrators');$o|ConvertTo-Json -Depth 4 -Compress
